import{c as r,Q as o,j as e,m as d}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"机器人","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/bot.md","filePath":"zh/getting-started/bot.md","lastUpdated":1778736656000}'),a={name:"zh/getting-started/bot.md"};function n(s,t,l,i,g,h){return o(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="机器人" tabindex="-1">机器人 <a class="header-anchor" href="#机器人" aria-label="Permalink to &quot;机器人&quot;">​</a></h1><p>机器人是 Memoh 里<strong>独立</strong>的智能体：自带 workspace、长期记忆、可配性格，并能通过各 <strong>渠道</strong> 对话、用工具做事。</p><h2 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h2><ol><li>侧栏进入 <strong>Bots</strong>。</li><li>点 <strong>Create Bot</strong>。</li><li>基本信息： <ul><li><strong>Display Name</strong>：对外的名字</li><li><strong>Avatar</strong>：头像 URL</li><li><strong>Timezone</strong>：可空；不填则继承用户或系统时区</li><li><strong>ACL Preset</strong>：如 <code>allow_all</code> 只给自己用、<code>private_only</code> 等快捷策略</li></ul></li><li>创建。</li></ol><hr><h2 id="详情页" tabindex="-1">详情页 <a class="header-anchor" href="#详情页" aria-label="Permalink to &quot;详情页&quot;">​</a></h2><p>点卡片进 <strong>详情</strong>，各 tab 管不同事：</p><table tabindex="0"><thead><tr><th>Tab</th><th>内容</th></tr></thead><tbody><tr><td><strong>Overview</strong></td><td>workspace runtime、库、渠道、记忆等健康检查</td></tr><tr><td><strong>General</strong></td><td>主模型/标题/生图、记忆/搜索/浏览器/TTS、时区、语言、推理、危险区</td></tr><tr><td><strong>Container</strong></td><td>容器型 workspace 起停、快照、导入导出</td></tr><tr><td><strong>Desktop</strong></td><td>Workspace display runtime、有头浏览器、实时 display session</td></tr><tr><td><strong>Network</strong></td><td>Workspace 网络与 overlay provider 状态/动作</td></tr><tr><td><strong>Tool Approval</strong></td><td>需要人类确认的工具审批设置</td></tr><tr><td><strong>Memory</strong></td><td>浏览、搜、建、改、压记忆</td></tr><tr><td><strong>Platforms</strong></td><td>各消息渠道（Telegram、Discord、飞书等）</td></tr><tr><td><strong>Access</strong></td><td>ACL 与默认通过/拒绝</td></tr><tr><td><strong>Email</strong></td><td>邮服绑定、发件箱</td></tr><tr><td><strong>Terminal</strong></td><td>进入 workspace runtime 的交互 shell</td></tr><tr><td><strong>Files</strong></td><td>workspace 文件管理</td></tr><tr><td><strong>MCP</strong></td><td>连接（Stdio/Remote/OAuth）</td></tr><tr><td><strong>Heartbeat</strong></td><td>心跳间隔、模型、执行日志</td></tr><tr><td><strong>Compaction</strong></td><td>会话压缩设置与记录</td></tr><tr><td><strong>Schedule</strong></td><td>cron 与日志</td></tr><tr><td><strong>Skills</strong></td><td>技能 Markdown</td></tr></tbody></table><hr><h2 id="核心先配什么" tabindex="-1">核心先配什么 <a class="header-anchor" href="#核心先配什么" aria-label="Permalink to &quot;核心先配什么&quot;">​</a></h2><ol><li>打开机器人 <strong>General</strong>，先管模型与各类绑定。</li><li><strong>Heartbeat</strong> 管周期自主跑。</li><li><strong>Compaction</strong> 管会话写不长时的压缩。</li><li><strong>Access</strong> 在 ACL 预设之后细调。</li></ol><p>若这些资源还没有，先建好：</p><ul><li><a href="/zh/getting-started/provider-and-model.html">供应商与模型</a></li><li><a href="/zh/memory-providers/builtin.html">内置记忆提供方</a>（如用）</li><li><a href="/zh/getting-started/search-provider.html">搜索提供方</a></li><li><a href="/zh/tts-providers/index.html">TTS 提供方</a></li></ul><hr><h2 id="general-字段" tabindex="-1">General 字段 <a class="header-anchor" href="#general-字段" aria-label="Permalink to &quot;General 字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Chat Model</strong></td><td>主对话模型</td></tr><tr><td><strong>Title Model</strong></td><td>可选，生成会话标题</td></tr><tr><td><strong>Image Generation Model</strong></td><td>可选，需带 <code>image-output</code> 的聊天模型</td></tr><tr><td><strong>Memory Provider</strong></td><td>长期记忆后端；内置类型还可自带记忆/向量模型</td></tr><tr><td><strong>Search Provider</strong></td><td>联网搜索用哪家</td></tr><tr><td><strong>TTS Model</strong></td><td>来自 TTS 流，不是普通 chat 供应商里选</td></tr><tr><td><strong>Timezone</strong></td><td>不填则用户时区再落到系统</td></tr><tr><td><strong>Language</strong></td><td>机器人主用语</td></tr><tr><td><strong>Reasoning Enabled</strong></td><td>当前 chat 模型有 <code>reasoning</code> 时可用</td></tr><tr><td><strong>Reasoning Effort</strong></td><td><code>low</code> / <code>medium</code> / <code>high</code></td></tr></tbody></table><p>注意：</p><ul><li><strong>生图模型</strong> 故意与主聊天模型分开，好单独换「更擅长出图」的。</li><li><strong>TTS</strong> 在 <a href="/zh/tts-providers/">TTS 提供方</a> 里用 <code>speech</code> 模型，例如 Edge。</li><li><code>context_window</code> 会影响状态栏展示和 <a href="/zh/getting-started/compaction.html">会话压缩</a> 的体感。</li></ul><hr><h2 id="heartbeat-字段" tabindex="-1">Heartbeat 字段 <a class="header-anchor" href="#heartbeat-字段" aria-label="Permalink to &quot;Heartbeat 字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Heartbeat Enabled</strong></td><td>开不开周期自主</td></tr><tr><td><strong>Interval</strong></td><td>多少分钟一次</td></tr><tr><td><strong>Heartbeat Model</strong></td><td>可与主 chat 不同</td></tr></tbody></table><p>同 tab 可看各次执行日志。</p><hr><h2 id="compaction-相关-此处指「会话」" tabindex="-1">Compaction 相关（此处指「会话」） <a class="header-anchor" href="#compaction-相关-此处指「会话」" aria-label="Permalink to &quot;Compaction 相关（此处指「会话」）&quot;">​</a></h2><p>这里说的是 <strong>当前会话</strong> 的上下文压短，不是改记忆条目的那种。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Compaction Enabled</strong></td><td>是否自动在会话里压摘要</td></tr><tr><td><strong>Compaction Threshold</strong></td><td>触发的估算 token 阈值</td></tr><tr><td><strong>Compaction Ratio</strong></td><td>压多狠</td></tr><tr><td><strong>Compaction Model</strong></td><td>可选，专门做摘要的模型</td></tr></tbody></table><p>细节见 <a href="/zh/getting-started/compaction.html">会话上下文压缩</a>。</p><hr><h2 id="访问与-acl" tabindex="-1">访问与 ACL <a class="header-anchor" href="#访问与-acl" aria-label="Permalink to &quot;访问与 ACL&quot;">​</a></h2><p>创建时先给一个 <strong>ACL 预设</strong>，之后在 <strong>Access</strong> 里微调。<strong>预设</strong> 给一版默认策略，<strong>Default Effect</strong> 管「没命中规则时」放行还是挡。</p><p><a href="/zh/getting-started/sessions.html">会话</a> 与 Discuss 的默认行为在那一页。若你用 API/自动化，配置里还可能有 <code>discuss_probe_model_id</code> 等进阶项，日常创建不必先动。</p><hr><h2 id="终端" tabindex="-1">终端 <a class="header-anchor" href="#终端" aria-label="Permalink to &quot;终端&quot;">​</a></h2><p><strong>Terminal</strong> tab 开交互 shell，可多 tab；workspace runtime 正在运行时才能用。</p><hr><h2 id="删除" tabindex="-1">删除 <a class="header-anchor" href="#删除" aria-label="Permalink to &quot;删除&quot;">​</a></h2><p><strong>General</strong> 最下 <strong>Danger Zone</strong> -&gt; <strong>Delete Bot</strong>，会删掉该机器人相关数据（含 workspace 文件与记忆等），<strong>不可恢复</strong>。</p>',37)])])}const m=r(a,[["render",n]]);export{p as __pageData,m as default};
